INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('b16c4b1c-b45e-470d-a1a5-d6f87424d410', 'Hvilke av disse faktorene tror du har størst innflytelse på sykefraværet der du jobber?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('61a9a84a-949b-4f46-97e5-c9b60e01d433', 'Velg det tiltaket som du mener best kan bidra til å forebygge sykefraværet', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('62b3a863-cba3-4c92-8c7e-19d8b4688d49', 'Vi har kunnskap og ferdigheter til å gjennomføre forbedringstiltak i virksomheten (planlegge tiltak, gjennomføre og evaluere måloppnåelse)', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('5df90163-81e4-44c5-8e72-9b47f2added2', 'I hvilken grad jobber dere med tilrettelegging og tilpasning av arbeid?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018e7b0a-4455-739d-b377-870e01fe978f', 'Hvor lenge har du vært en del av gruppen?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018e7b0b-2490-7295-9ab4-aca881c46320', 'Hvor ofte møtes dere?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018e7b12-b11a-7f68-b617-e694fd010088', 'Hvor godt kjenner dere til hverandres roller og ansvar i gruppen?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018e7b15-256d-705e-a3e9-913e56658b28', 'Hvordan opplever du at samarbeidet i gruppen fungerer?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018e7b17-4004-7c54-a1ab-d352a87be133', 'I hvilken grad er du involvert i den daglige driften?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018e7b18-2552-77e9-95a1-366c3eb8e800', 'I hvilken grad er du involvert i å skape godt samarbeid på arbeidsplassen?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018e7b0d-fe32-79ab-8e2e-b990afbbc2bf', 'Hvilke temaer får størst prioritet i møtene deres?', true);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e25-6a40-79c6-bb29-68de8b575cd1', 'Vi planlegger og gjennomfører jevnlige møter i partssamarbeidet', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e25-6a40-713f-b769-267afa134896', 'Hvilke temaer vektlegges mest i møtene?', true);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e25-6a40-7c73-8183-cc574b92b2be', 'Hvordan opplever du at partssamarbeidet fungerer?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e25-6a40-78d9-9ad6-775fec6a102f', 'Som leder, tillitsvalgt eller verneombud jobber jeg for et godt samarbeid på arbeidsplassen', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e5d-c06d-775f-8304-8afa7bf193d1', 'Vi jobber systematisk for å forebygge sykefravær', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e5e-18b2-7bf9-a714-ea5554f213d7', 'Vi har sykefraværsrutiner som er kjent for alle og blir brukt', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e5e-51bb-7a64-9bca-452ab06ae313', 'Ansatte kjenner til egne plikter og rettigheter når de er sykmeldt eller står i fare for å bli det', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e5e-6b80-7332-8491-359b2985d8a0', 'Jeg opplever at ledere er trygge på å følge opp ansatte som er sykmeldt eller står i fare for å bli det', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e5e-84bf-7123-adb2-f80af15c954f', 'Vi har skriftlig oversikt over tilretteleggingsmuligheter for ansatte', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e5e-9ce6-74c6-9e9d-c6a9b49075b9', 'Tilretteleggingstiltak er midlertidig og avsluttes til avtalt tid ', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e5e-b178-7d83-aa0b-ddb52cade105', 'Jeg har inntrykk av at vi har mange vanskelige enkeltsaker som handler om sykefravær', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e7b-5689-7ff7-884f-2635a51009ef', 'Vi er kjent med hva som er de vanlige risikofaktorene for vår bransje', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('018f4e7b-5689-7595-932f-06a4ee599efc', 'Vi jobber systematisk med tiltak for å forbedre arbeidsmiljøet', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('0192bedd-7815-7abf-ae8d-f04f4aed97df', 'Vi har konkretiserte planer for hvordan vi i partssamarbeidet skal samarbeide fremover', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('0192bee0-6437-7302-a16e-79a1e9e62d5b', 'Jeg opplever at vi er motiverte for å samarbeide om å forebygge sykefravær og utvikle arbeidsmiljøet', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('0192bee1-c50d-76b8-850f-100d810ad6c3', 'Jeg opplever at vi har nødvendige verktøy for å samarbeide om å forebygge sykefravær og utvikle arbeidsmiljøet', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('0192bee3-ea9e-7366-877e-c52e03060d40', 'Opplever du at samarbeidet om forebyggende sykefraværsarbeid bidrar til redusert sykefravær?', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('0192bee5-0bf8-74a9-9569-ee9118d4bdb6', 'Vi er motiverte for å videreutvikle arbeidsmiljøet vårt', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('0192bee6-55aa-7281-b18d-d519c9d0d86c', 'Vi har fått et godt grunnlag for å videreutvikle arbeidsmiljøet vårt', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('0192bee7-557b-7611-9c2a-6fb8c72691bc', 'Jeg tror det forebyggende arbeidet vil gi oss et bedre et arbeidsmiljø', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('01932f4c-38f5-7083-a38d-41dc664866d3', 'Vi planlegger og gjennomfører jevnlige møter i partssamarbeidet', false);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('01932f59-7a00-7c2e-acb5-c6709503d92c', 'Hvilke temaer vektlegges mest i møtene?', true);
INSERT INTO public.ia_sak_kartlegging_sporsmal VALUES ('01932f63-597d-73c4-976b-723bba329c57', 'Hvordan opplever du at partssamarbeidet fungerer?', false);
